import React, { useState } from "react";
import type { RivieraJugadorNivel } from "../../lib/rivieraJugadores/types";
import { JUGADOR_NIVEL_LABELS } from "../../lib/rivieraJugadores/constants";

const NIVELES = Object.keys(JUGADOR_NIVEL_LABELS) as RivieraJugadorNivel[];

interface NuevoJugadorModalProps {
  open: boolean;
  onClose: () => void;
  onSubmit: (data: {
    nombre: string;
    email?: string;
    telefono?: string;
    nivel: RivieraJugadorNivel;
  }) => Promise<void>;
}

export const NuevoJugadorModal: React.FC<NuevoJugadorModalProps> = ({
  open,
  onClose,
  onSubmit,
}) => {
  const [nombre, setNombre] = useState("");
  const [email, setEmail] = useState("");
  const [telefono, setTelefono] = useState("");
  const [nivel, setNivel] = useState<RivieraJugadorNivel>("intermedio");
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);

  if (!open) return null;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!nombre.trim()) return;
    setSaving(true);
    setError(null);
    try {
      await onSubmit({
        nombre: nombre.trim(),
        email: email.trim() || undefined,
        telefono: telefono.trim() || undefined,
        nivel,
      });
      setNombre("");
      setEmail("");
      setTelefono("");
      setNivel("intermedio");
      onClose();
    } catch (err) {
      setError(err instanceof Error ? err.message : "No se pudo crear el jugador");
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="rj-modal-backdrop" role="presentation" onClick={onClose}>
      <div
        className="rj-modal"
        role="dialog"
        aria-labelledby="rj-modal-title"
        onClick={(e) => e.stopPropagation()}
      >
        <h2 id="rj-modal-title">Nuevo jugador</h2>
        <form onSubmit={handleSubmit}>
          <div className="rj-field">
            <label htmlFor="rj-nombre">Nombre *</label>
            <input
              id="rj-nombre"
              value={nombre}
              onChange={(e) => setNombre(e.target.value)}
              autoFocus
              required
            />
          </div>
          <div className="rj-field">
            <label htmlFor="rj-email">Email</label>
            <input
              id="rj-email"
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
            />
          </div>
          <div className="rj-field">
            <label htmlFor="rj-tel">Teléfono / WhatsApp</label>
            <input
              id="rj-tel"
              value={telefono}
              onChange={(e) => setTelefono(e.target.value)}
            />
          </div>
          <div className="rj-field">
            <label htmlFor="rj-nivel">Categoría</label>
            <select
              id="rj-nivel"
              value={nivel}
              onChange={(e) => setNivel(e.target.value as RivieraJugadorNivel)}
            >
              {NIVELES.map((n) => (
                <option key={n} value={n}>
                  {JUGADOR_NIVEL_LABELS[n]}
                </option>
              ))}
            </select>
          </div>
          {error && (
            <p style={{ color: "#ff3b30", fontSize: "0.8125rem" }}>{error}</p>
          )}
          <div className="rj-modal__actions">
            <button type="button" className="rj-btn rj-btn--ghost" onClick={onClose}>
              Cancelar
            </button>
            <button
              type="submit"
              className="rj-btn rj-btn--primary"
              disabled={saving || !nombre.trim()}
            >
              {saving ? "Guardando…" : "Crear"}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};
